(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>\"]/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"step-cadence",fields:[{"key":"steps","label":"총 걸음 수","type":"integer","placeholder":"","default":"","options":[],"raw":false},{"key":"minutes","label":"운동시간 (분)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var s=Number(x.steps),m=Number(x.minutes);if(![s,m].every(Number.isFinite)||!Number.isInteger(s)||s<0||m<=0)return{error:"걸음 수는 0 이상 정수, 시간은 0보다 크게 입력해 주세요."};return{cadence:s/m,stepsPerSecond:s/(m*60),steps:s};},format:function(r,api){return api.resultCard("케이던스",api.formatNumber(r.cadence,1)+"보/분",api.formatNumber(r.stepsPerSecond,3)+"보/초");}},{id:"running-even-split",fields:[{"key":"distanceKm","label":"총 거리 (km)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"totalMinutes","label":"목표시간 (분)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"splitKm","label":"구간 거리 (km)","type":"number","placeholder":"","default":"1","options":[],"raw":false}],hint:"",compute:function(x){var d=Number(x.distanceKm),t=Number(x.totalMinutes),s=Number(x.splitKm);if(![d,t,s].every(Number.isFinite)||d<=0||t<=0||s<=0)return{error:"거리와 시간은 0보다 크게 입력해 주세요."};return{paceMinPerKm:t/d,splitMinutes:t/d*s,fullSplits:Math.floor(d/s),remainingKm:d% s};},format:function(r,api){return api.resultCard("1km 페이스",api.formatNumber(r.paceMinPerKm,3)+"분/km","")+api.resultCard("구간 목표기록",api.formatNumber(r.splitMinutes,3)+"분","완전 구간 "+r.fullSplits+"개");}},{id:"sleep-efficiency",fields:[{"key":"timeInBedMinutes","label":"침대에 머문 시간 (분)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"sleepMinutes","label":"실제 수면시간 (분)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"의학적 진단이 아닌 기록 정리용 계산입니다.",compute:function(x){var b=Number(x.timeInBedMinutes),s=Number(x.sleepMinutes);if(![b,s].every(Number.isFinite)||b<=0||s<0||s>b)return{error:"침대시간은 0보다 크게, 수면시간은 침대시간 이하로 입력해 주세요."};return{sleepEfficiency:s/b*100,awakeMinutes:b-s,sleepHours:s/60};},format:function(r,api){return api.resultCard("수면 효율",api.formatNumber(r.sleepEfficiency,2)+"%","실제 수면 "+api.formatNumber(r.sleepHours,2)+"시간")+api.resultCard("깨어 있던 시간",api.formatNumber(r.awakeMinutes,0)+"분","");}},{id:"sleep-cycle-bedtime",fields:[{"key":"wakeTime","label":"기상시각","type":"number","placeholder":"","default":"420","options":[],"raw":false},{"key":"cycles","label":"수면주기 수","type":"integer","placeholder":"","default":"5","options":[],"raw":false},{"key":"cycleMinutes","label":"주기 길이 (분)","type":"number","placeholder":"","default":"90","options":[],"raw":false},{"key":"sleepLatency","label":"잠드는 시간 (분)","type":"number","placeholder":"","default":"15","options":[],"raw":false}],hint:"기상시각은 예: 오전 7시 = 420분으로 입력합니다.",compute:function(x){var w=Number(x.wakeTime),c=Number(x.cycles),m=Number(x.cycleMinutes),l=Number(x.sleepLatency);if(![w,c,m,l].every(Number.isFinite)||w<0||w>=1440||!Number.isInteger(c)||c<=0||m<=0||l<0)return{error:"기상시각은 자정 후 분(0~1439), 주기 수는 양의 정수로 입력해 주세요."};var bed=(w-c*m-l)%1440;if(bed<0)bed+=1440;return{bedMinutes:bed,sleepDurationMinutes:c*m,totalInBedMinutes:c*m+l};},format:function(r,api){function tm(v){var h=Math.floor(v/60),m=Math.round(v%60);return String(h).padStart(2,"0")+":"+String(m).padStart(2,"0");}return api.resultCard("예상 취침시각",tm(r.bedMinutes),"수면 "+api.formatNumber(r.sleepDurationMinutes/60,2)+"시간")+api.resultCard("침대에 들어갈 총시간",api.formatNumber(r.totalInBedMinutes,0)+"분","");}},{id:"sweat-fluid-replacement",fields:[{"key":"preWeightKg","label":"운동 전 체중 (kg)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"postWeightKg","label":"운동 후 체중 (kg)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"fluidIntakeLiters","label":"운동 중 섭취량 (L)","type":"number","placeholder":"","default":"0","options":[],"raw":false},{"key":"urineLiters","label":"운동 중 소변량 (L)","type":"number","placeholder":"","default":"0","options":[],"raw":false},{"key":"durationHours","label":"운동시간 (시간)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"음수 결과는 측정오차 또는 입력값을 다시 확인하세요. 개인 건강상태에 따라 전문가 지침을 우선합니다.",compute:function(x){var a=Number(x.preWeightKg),b=Number(x.postWeightKg),i=Number(x.fluidIntakeLiters),u=Number(x.urineLiters),h=Number(x.durationHours);if(![a,b,i,u,h].every(Number.isFinite)||a<=0||b<=0||i<0||u<0||h<=0)return{error:"체중과 운동시간은 0보다 크게, 수분량은 0 이상으로 입력해 주세요."};var loss=(a-b)+i-u;return{sweatLossLiters:loss,sweatRateLitersPerHour:loss/h,weightChangePercent:(a-b)/a*100};},format:function(r,api){return api.resultCard("추정 땀 손실량",api.formatNumber(r.sweatLossLiters,3)+"L","시간당 "+api.formatNumber(r.sweatRateLitersPerHour,3)+"L")+api.resultCard("체중 변화",api.formatNumber(r.weightChangePercent,2)+"%","");}},{id:"workout-volume",fields:[{"key":"sets","label":"세트 수","type":"integer","placeholder":"","default":"","options":[],"raw":false},{"key":"reps","label":"세트당 반복 수","type":"integer","placeholder":"","default":"","options":[],"raw":false},{"key":"weightKg","label":"사용 중량 (kg)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var s=Number(x.sets),r=Number(x.reps),w=Number(x.weightKg);if(![s,r,w].every(Number.isFinite)||!Number.isInteger(s)||!Number.isInteger(r)||s<=0||r<=0||w<0)return{error:"세트와 반복 수는 0보다 큰 정수, 중량은 0 이상으로 입력해 주세요."};return{volumeKg:s*r*w,totalReps:s*r,averageLoadKg:w};},format:function(r,api){return api.resultCard("총 훈련 볼륨",api.formatNumber(r.volumeKg,1)+"kg","총 반복 "+r.totalReps+"회")+api.resultCard("반복당 중량",api.formatNumber(r.averageLoadKg,1)+"kg","");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
